function openRoleModal(){document.getElementById("roleModal").classList.remove("hidden")}function closeRoleModal(){document.getElementById("roleModal").classList.add("hidden"),document.getElementById("roleForm").reset()}async function createRole(e){e.preventDefault();const o=document.getElementById("submitRoleBtn"),t=document.getElementById("roleName").value.toUpperCase();o.disabled=!0,o.innerText="Creando...";try{const s=await fetch("/admin/roles",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:t})});if(s.ok){const n=document.querySelector('select[name="role"]'),a=new Option(t,t);n.add(a),n.value=t,closeRoleModal(),showToast("Rol creado con \xE9xito")}else{const n=await s.json();peakAlert("Error",n.error||"No se pudo crear el rol","error")}}catch{peakAlert("Error de conexi\xF3n","No se pudo conectar con el servidor","error")}finally{o.disabled=!1,o.innerText="Crear Rol"}}async function deleteRole(e){if(await peakConfirm({title:`\xBFEliminar rol "${e}"?`,text:"Se verificar\xE1 que ning\xFAn usuario tenga este rol asignado. Si alguien lo tiene, no podr\xE1 eliminarse.",confirmText:"S\xED, eliminar",type:"danger"}))try{const r=await fetch("/admin/roles",{method:"DELETE",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:e})}),t=await r.json();r.ok?(showToast("Rol eliminado con \xE9xito"),setTimeout(()=>window.location.reload(),800)):peakAlert("No se puede eliminar",t.error,"warning")}catch{peakAlert("Error","Error de conexi\xF3n con el servidor","error")}}async function revokeAccess(e,o){if(await peakConfirm({title:"\xBFRevocar acceso?",text:"El usuario perder\xE1 todos sus roles en esta aplicaci\xF3n.",confirmText:"S\xED, revocar",type:"danger"}))try{(await fetch(`/admin/apps/${e}/users/${o}`,{method:"DELETE"})).ok?(showToast("Acceso revocado"),setTimeout(()=>window.location.reload(),800)):peakAlert("Error","No se pudo revocar el acceso","error")}catch{peakAlert("Error","Error de conexi\xF3n","error")}}async function assignUser(e,o){e.preventDefault();const r=e.target,t=r.email.value,s=r.role.value,n=r.querySelector('button[type="submit"]');n.disabled=!0;try{const a=new URLSearchParams;a.append("email",t),a.append("role",s);const i=await fetch(`/admin/apps/${o}/users`,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:a});if(i.ok)await peakAlert("\xC9xito","Usuario y Rol vinculados correctamente a esta aplicaci\xF3n.","success"),window.location.reload();else{let c="Error al vincular usuario";try{c=(await i.json()).error||c}catch{c=await i.text()}peakAlert("Error al vincular",c,"error")}}catch{peakAlert("Servidor Inaccesible","Problema al conectar con el backend.","error")}finally{n.disabled=!1}}async function unlockUser(e,o){try{(await fetch(`/admin/apps/${e}/users/${o}/unlock`,{method:"POST"})).ok?(showToast("Usuario habilitado correctamente"),setTimeout(()=>window.location.reload(),800)):peakAlert("Error","No se pudo habilitar al usuario","error")}catch{peakAlert("Error","Error de conexi\xF3n","error")}}document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("openRoleModalBtn"),o=document.getElementById("closeRoleModalBtn"),r=document.getElementById("roleModalBackdrop");e&&e.addEventListener("click",openRoleModal),o&&o.addEventListener("click",closeRoleModal),r&&r.addEventListener("click",closeRoleModal)});
